import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { Subject } from 'rxjs';
import { permissionsLabels } from 'src/app/shared/models/fmosNewRolePermissions';
import { ApiService } from 'src/app/shared/services/api.service';
import { ChargeMaintenanceService } from 'src/app/shared/services/charge-maintenance-service.service';
import { RoleService } from 'src/app/shared/services/role.service';

@Component({
  selector: 'npr-charge-maintainence-summary',
  templateUrl: './charge-maintainence-summary.component.html',
  styleUrls: ['./charge-maintainence-summary.component.scss']
})
export class ChargeMaintainenceSummaryComponent implements OnInit {

  respArray: any[] = [];
  roleCodes = new permissionsLabels();
  dtOptions: DataTables.Settings = {};
  dtTrigger: Subject<any> = new Subject<any>();
  constructor( private roleService: RoleService,private apiService: ChargeMaintenanceService,private router:Router) {}

  ngOnInit(): void {
    setTimeout(() => {
      this.newRolePermissions();
    }, 2000);
    this.roleService.screenLabelList.subscribe(message => this.roleCodes = message);
    setTimeout(() => {
      console.log(this.roleCodes);
    }, 3000);
  
    this.getChargeMaintainenceSummary();
    this.dtOptions = {
      pagingType: "full_numbers",
      pageLength: 5,
      processing: true, 
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]]
    };
  }
  newRolePermissions()
  {

    this.roleService.fetchScreenPermissions('Charge Maintenance');
  }
  getChargeMaintainenceSummary() {
    this.apiService.gettingChargeMaintenance().subscribe((dataresp) => {
      console.log(dataresp);
      this.respArray = dataresp;
      this.dtTrigger.next();
    });
  }
  ngOnDestroy(): void {
    this.dtTrigger.unsubscribe();
  }
  new(){
   
    this.apiService.setIndex({
      index: "",
    });
    this.router.navigateByUrl("/charge-maintainence/create");
  }
  edit(data){
    this.apiService.setIndex({
      index: data.id,
    });
    this.router.navigateByUrl("/charge-maintainence/create");
  }

}
